// dish.service.ts
import { Injectable } from '@angular/core';
import { BaseService } from '../Base/base.service';
import { map, Observable } from 'rxjs';
import { Dish } from '../../models';

export type CreateDishData = Omit<Dish, 'id' | 'created_at' | 'restaurant_id'>;

@Injectable({ providedIn: 'root' })
export class DishService extends BaseService<Dish> {

  protected getTableName(): string { return 'dishes'; }

  // ── Override loadData: aggiunge filtro soft-delete ──
  override async loadData(additionalFilters?: Record<string, any>): Promise<void> {
    try {
      this.loadingSubject.next(true);
      this.errorSubject.next(null);

      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) { this.dataSubject.next([]); return; }

      let query = this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('restaurant_id', restaurantId)
        .is('deleted_at', null); // 🔥 soft-delete filter

      if (additionalFilters) {
        Object.entries(additionalFilters).forEach(([key, val]) => {
          if (val !== null && val !== undefined) query = query.eq(key, val);
        });
      }

      const { data, error } = await this.run(query);
      if (error) throw error;
      this.dataSubject.next(data ?? []);
    } catch (err: any) {
      this.handleError('loadData', err);
      this.dataSubject.next([]);
    } finally {
      this.loadingSubject.next(false);
    }
  }

  // ══════════════════════════════════════════════════
  // CRUD — ora usa BaseService.create() e BaseService.update()
  // ══════════════════════════════════════════════════

  async createDish(dishData: CreateDishData): Promise<Dish | null> {
    if (!dishData.name?.trim()) {
      this.errorSubject.next('Il nome del piatto è obbligatorio');
      return null;
    }
    if (dishData.base_price <= 0) {
      this.errorSubject.next('Il prezzo base deve essere maggiore di 0');
      return null;
    }

    // BaseService.create() aggiunge restaurant_id, created_at, updated_at automaticamente
    return this.create({
      name: dishData.name.trim(),
      description: dishData.description || null,
      base_price: Number(dishData.base_price),
      food_cost: dishData.food_cost ? Number(dishData.food_cost) : 0,
      status: dishData.status || 'available',
      preparation_time: dishData.preparation_time || null,
      category_id: dishData.category_id || null,
      delivery_price: dishData.delivery_price || null,
      takeaway_price: dishData.takeaway_price || null,
      image_url: dishData.image_url || null,
      recipe_instructions: dishData.recipe_instructions || null,
      ingredients_composition: dishData.ingredients_composition || null,
      allergens: dishData.allergens || [],
    });
  }

  async updateDish(id: string, updates: Partial<Dish>): Promise<boolean> {
    if (updates.name !== undefined && !updates.name.trim()) {
      this.errorSubject.next('Il nome del piatto non può essere vuoto');
      return false;
    }
    if (updates.base_price !== undefined && updates.base_price <= 0) {
      this.errorSubject.next('Il prezzo base deve essere maggiore di 0');
      return false;
    }
    // BaseService.update() gestisce updated_at + restaurant_id check + refresh
    return this.update(id, updates);
  }

  /** Soft delete */
  async deleteDish(id: string): Promise<boolean> {
    return this.updateDish(id, { deleted_at: new Date().toISOString() });
  }

  /** Ripristina da soft delete */
  async restoreDish(id: string): Promise<boolean> {
    return this.updateDish(id, { deleted_at: null, status: 'available' });
  }

  // ══════════════════════════════════════════════════
  // ALIAS mantenuti per compatibilità con i componenti
  // ══════════════════════════════════════════════════

  async loadDishes(): Promise<void> { return this.loadData(); }
  async reloadDishes(): Promise<void> { return this.loadData(); }
  getDishes(): Dish[] { return this.dataSubject.value; }

  // ══════════════════════════════════════════════════
  // OBSERVABLE STREAMS
  // ══════════════════════════════════════════════════

  getAvailableDishes(): Observable<Dish[]> {
    return this.data$.pipe(map(d => d.filter(dish => dish.status === 'available')));
  }

  getActiveDishes$(): Observable<Dish[]> {
    return this.data$.pipe(map(d => d.filter(dish => !dish.deleted_at)));
  }

  getDishesByCategory(categoryId: string): Observable<Dish[]> {
    return this.data$.pipe(map(d => d.filter(dish => dish.category_id === categoryId)));
  }

  getDishById$(id: string): Observable<Dish | null> {
    return this.getById(id);
  }

  searchDishes(searchTerm: string): Observable<Dish[]> {
    return this.data$.pipe(
      map(dishes => {
        if (!searchTerm.trim()) return dishes;
        const term = searchTerm.toLowerCase();
        return dishes.filter(d =>
          d.name.toLowerCase().includes(term) ||
          d.description?.toLowerCase().includes(term)
        );
      })
    );
  }

  // Mantenuto per compatibilità — delega a MenuDishService idealmente
  getDishesByMenu$(menuId: string): Observable<Dish[]> {
    return this.data$;
  }

  // Mantenuto per compatibilità — logica semplificata
  isDishInMenu$(dishId: string, menuId: string): Observable<boolean> {
    return this.data$.pipe(map(dishes => dishes.some(d => d.id === dishId)));
  }

  // ══════════════════════════════════════════════════
  // UTILITY SINCRONI
  // ══════════════════════════════════════════════════

  getActiveDishes(): Dish[] {
    return this.dataSubject.value.filter(d => !d.deleted_at);
  }

  getDishById(id: string): Dish | undefined {
    return this.dataSubject.value.find(d => d.id === id);
  }

  // ══════════════════════════════════════════════════
  // AZIONI SPECIFICHE
  // ══════════════════════════════════════════════════

  async changeDishStatus(id: string, status: Dish['status']): Promise<boolean> {
    return this.updateDish(id, { status });
  }

  async updateFoodCost(id: string, foodCost: number): Promise<boolean> {
    if (foodCost < 0) {
      this.errorSubject.next('Il food cost non può essere negativo');
      return false;
    }
    return this.updateDish(id, { food_cost: foodCost });
  }

  async cloneDish(dishId: string, targetMenuName?: string): Promise<Dish | null> {
    const original = this.dataSubject.value.find(d => d.id === dishId && !d.deleted_at);
    if (!original) return null;

    const { id, created_at, deleted_at, ...dishData } = original;
    const baseName = dishData.name.replace(/ \(Copia.*\)$/, '').replace(/ - .*$/, '');
    const copies = this.dataSubject.value.filter(d =>
      d.name.startsWith(baseName) && d.id !== dishId && !d.deleted_at
    );
    const suffix = targetMenuName ?? 'Copia';
    const newName = copies.length > 0
      ? `${baseName} - ${suffix} (${copies.length + 1})`
      : `${baseName} - ${suffix}`;

    return this.createDish({ ...dishData, name: newName, status: 'available' });
  }

  async uploadDishImage(dishId: string, file: File): Promise<string | null> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return null;

    const supabase = this.supabaseService.getSupabaseClient();
    const safeName = file.name
      .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
      .replace(/[^a-zA-Z0-9.\-_]/g, '_').replace(/_+/g, '_').toLowerCase();
    const path = `restaurants/${restaurantId}/dishes/${dishId}_${Date.now()}_${safeName}`;

    const { error: uploadError } = await supabase.storage
      .from('restaurant-images').upload(path, file, { upsert: true });

    if (uploadError) { this.handleError('uploadDishImage', uploadError); return null; }

    const { data: { publicUrl } } = supabase.storage
      .from('restaurant-images').getPublicUrl(path);

    const ok = await this.updateDish(dishId, { image_url: publicUrl });
    return ok ? publicUrl : null;
  }

  async getAllDishesIncludingDeleted(): Promise<Dish[]> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return [];
    const { data, error } = await this.supabaseService.getSupabaseClient()
      .from('dishes').select('*').eq('restaurant_id', restaurantId);
    if (error) { this.handleError('getAllDishesIncludingDeleted', error); return []; }
    return data || [];
  }

  private async getDefaultCategoryId(): Promise<string | null> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return null;
    const supabase = this.supabaseService.getSupabaseClient();

    const { data } = await supabase.from('categories')
      .select('id').eq('restaurant_id', restaurantId)
      .eq('is_default', true).limit(1).single();
    if (data) return data.id;

    const { data: first } = await supabase.from('categories')
      .select('id').eq('restaurant_id', restaurantId).limit(1).single();
    return first?.id || null;
  }
}